// Fetch weather + marine data for a lat/lon position.
// Returns Result: { ok: true, data } on success, { ok: false, error: { code, message } } on failure.
async function fetchWeather(lat: number, lon: number) {
  try {
    // Conversion factor: meters per second to knots
    const MS_TO_KNOTS = 1.94384;
    const forecastHours = config.get('DEFAULT_FORECAST_HOURS') || 48;

    // Build Open-Meteo API URL — request both atmospheric and marine data
    const weatherParams = [
      'temperature_2m', 'relative_humidity_2m', 'precipitation',
      'pressure_msl', 'cloud_cover', 'wind_speed_10m',
      'wind_direction_10m', 'wind_gusts_10m'
    ].join(',');

    const weatherUrl = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}`
      + `&current=${weatherParams}`
      + `&hourly=${weatherParams}`
      + `&wind_speed_unit=ms`
      + `&forecast_hours=${forecastHours}`
      + `&timezone=auto`;

    // Marine API for wave data — separate endpoint
    const marineParams = 'wave_height,wave_direction,wave_period';
    const marineUrl = `https://marine-api.open-meteo.com/v1/marine?latitude=${lat}&longitude=${lon}`
      + `&current=${marineParams}`
      + `&hourly=${marineParams}`
      + `&forecast_hours=${forecastHours}`
      + `&timezone=auto`;

    // Fetch both in parallel for speed
    const [weatherRes, marineRes] = await Promise.all([
      fetch(weatherUrl),
      fetch(marineUrl).catch(() => null) // Marine data may not be available inland
    ]);

    // API error — return a Result failure instead of throwing
    if (!weatherRes.ok) {
      return {
        ok: false,
        error: { code: 'WEATHER_API_ERROR', message: `Open-Meteo weather API error: ${weatherRes.status}` }
      };
    }

    const weatherData = await weatherRes.json();
    const marineData = marineRes && marineRes.ok ? await marineRes.json() : null;

    // Convert current conditions to nautical units
    const current = {
      temperature: weatherData.current.temperature_2m,           // °C
      humidity: weatherData.current.relative_humidity_2m,         // %
      precipitation: weatherData.current.precipitation,           // mm
      pressure: weatherData.current.pressure_msl,                 // hPa
      cloudCover: weatherData.current.cloud_cover,                // %
      windSpeed: Math.round(weatherData.current.wind_speed_10m * MS_TO_KNOTS * 10) / 10,  // kn
      windDirection: weatherData.current.wind_direction_10m,      // degrees
      windGusts: Math.round(weatherData.current.wind_gusts_10m * MS_TO_KNOTS * 10) / 10,  // kn
      // Marine data — null if unavailable (e.g. inland positions)
      waveHeight: marineData?.current?.wave_height ?? null,       // m
      waveDirection: marineData?.current?.wave_direction ?? null,  // degrees
      wavePeriod: marineData?.current?.wave_period ?? null,       // s
      time: weatherData.current.time
    };

    // Build hourly forecast array with converted wind speeds
    const hourly = weatherData.hourly.time.map((time: string, i: number) => ({
      time,
      temperature: weatherData.hourly.temperature_2m[i],
      humidity: weatherData.hourly.relative_humidity_2m[i],
      precipitation: weatherData.hourly.precipitation[i],
      pressure: weatherData.hourly.pressure_msl[i],
      cloudCover: weatherData.hourly.cloud_cover[i],
      windSpeed: Math.round(weatherData.hourly.wind_speed_10m[i] * MS_TO_KNOTS * 10) / 10,
      windDirection: weatherData.hourly.wind_direction_10m[i],
      windGusts: Math.round(weatherData.hourly.wind_gusts_10m[i] * MS_TO_KNOTS * 10) / 10,
      // Marine hourly data — may not exist
      waveHeight: marineData?.hourly?.wave_height?.[i] ?? null,
      waveDirection: marineData?.hourly?.wave_direction?.[i] ?? null,
      wavePeriod: marineData?.hourly?.wave_period?.[i] ?? null
    }));

    // Success — wrap payload in Result
    return {
      ok: true,
      data: { latitude: lat, longitude: lon, timezone: weatherData.timezone, current, hourly }
    };
  } catch (err) {
    // Catch unexpected errors (network failures, JSON parse errors, etc.)
    return {
      ok: false,
      error: { code: 'WEATHER_API_ERROR', message: err.message || 'Unexpected error fetching weather' }
    };
  }
}
